mapper.select:
SELECT BOARD.BOARD_NO, BOARD.TITLE, BOARD.CONT , BOARD.WRITER, BOARD.MODIFIER, BOARD.REG_DT , BOARD.MOD_DT, BOARD.DELETE_YN , DTL01.CODE_NM as BOARD_TYPE_NM , DTL02.CODE_NM as CATEGORY_NM , 0 AS CHK FROM HCNC.hcnc_board as BOARD LEFT OUTER JOIN HCNC.COM_CD_DTL as DTL01 ON BOARD.BOARD_TYPE = DTL01.CODE AND DTL01.PT_CODE = 'BOARD_TYPE' LEFT OUTER JOIN HCNC.COM_CD_DTL as DTL02 ON BOARD.CATEGORY = DTL02.CODE AND DTL02.PT_CODE = 'CATEGORY' WHERE 1=1
AND BOARD.BOARD_NO=#{boardNo}
AND ( BOARD.TITLE LIKE CONCAT('%', #{searchVal}, '%') OR BOARD.CONT LIKE CONCAT('%', #{searchVal}, '%') )
AND BOARD.TITLE LIKE CONCAT('%', #{searchVal}, '%')
AND BOARD.CONT LIKE CONCAT('%', #{searchVal}, '%')
AND BOARD.BOARD_TYPE=#{searchBoardType}
AND BOARD.CATEGORY=#{searchCategory}
AND BOARD.DELETE_YN = 'N'

mapper.update:
UPDATE HCNC.COM_CD_MST
	SET CODE_NM = #{CODE_NM}
WHERE CODE = #{CODE}

UPDATE HCNC.COM_CD_DTL
	SET CODE_NM = #{CODE_NM}
WHERE CODE = #{CODE}
	AND PT_CODE=#{PT_CODE}

UPDATE HCNC.HCNC_BOARD
	SET DELETE_YN = 'Y'
WHERE BOARD_NO = #{boardNo}

mapper.delete:
DELETE FROM HCNC.HCNC_BOARD
WHERE BOARD_NO IN

	#{boardNo}

DELETE FROM HCNC.COM_CD_DTL
WHERE CODE=#{code}
	AND PT_CODE=#{ptCode}
